    def findDuplicate(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        slow, fast = 0, 0
        # 先让两指针相遇，相遇时slow走过的距离就是环的长度
        while slow != fast or fast == 0:
            slow = nums[slow]
            fast = nums[nums[fast]]
        # slow从头再走，fast继续走，相当于fast比slow提前走了环长步，二者再次相遇时就是环的入口
        slow = 0
        while slow != fast:
            slow = nums[slow]
            fast = nums[fast]
        return slow
