class Codec:

    def serialize(self, root):
        """Encodes a tree to a single string.

        :type root: TreeNode
        :rtype: str
        """
        r = []
        q = []
        q.append(root)
        while q:
            root = q.pop(0)
            if root:
                r.append(str(root.val))
                q.append(root.left)
                q.append(root.right)
            else:
                r.append('#')  # 空节点
            r.append(' ') # 换层
        return ''.join(r)


    def deserialize(self, data):
        """Decodes your encoded data to tree.

        :type data: str
        :rtype: TreeNode
        """
        tree = data.split()
        if tree[0] == '#': #空节点
            return None
        q = []
        root = TreeNode(int(tree[0]))
        q.append(root)
        i = 1
        while q:
            cur = q.pop(0)
            if not cur:
                continue
            cur.left = TreeNode(int(tree[i])) if tree[i] != '#' else None
            cur.right = TreeNode(int(tree[i+1])) if tree[i+1] != '#' else None
            i += 2
            q.append(cur.left)
            q.append(cur.right)
        return root
