    def binaryInsert(self, num):
        l, r = 0, len(self.data) - 1
        while l <= r:
            if num >= self.data[r]:
                self.data.insert(r+1, num)
                return
            elif num <= self.data[l]:
                self.data.insert(l, num)
                return
