    def mergeSort(self, head):
        # 分裂链表到单个节点后不再分裂
        if not head.next:
            return head
        # 快慢指针查找中间点
        p, q, pre = head, head, None
        while q and q.next:
            pre = p
            p = p.next
            q = q.next.next
        # 分裂链表为两段，两段继续进行分裂
        pre.next = None
        l = self.mergeSort(head)
        r = self.mergeSort(p)
        return self.merge(l, r)

    def merge(self, l, r):
        # 归并
        head = ListNode(0)
        cur = head
        while l and r:
            if l.val <= r.val:
                cur.next = l
                cur = cur.next
                l = l.next
            else:
                cur.next = r
                cur = cur.next
                r = r.next
        if l:
            cur.next = l
        if r:
            cur.next = r
        return head.next

